INSERT INTO `plan_action` VALUES (110,'2026-06-18 20:21:51.466547','','2026-06-18 20:21:12.540712','CL001',NULL,NULL,'2026-06-19','Marquer d\'une pastille jaune avec la date de réclamation tous les modules présentant un problème technique.\n\nAutres non-conformités à traiter : 1. Mettre un marquage (pastille jaune avec date de réclamation) sur tout module présentant un problème [TECHNIQUE]\n2. Vérifier l’état des modules de test )cassées ou mal fixées ou manquantes), dégager les résidus s\'ils existent et vérifier l\'état des shtift (pin de test de continuité) et schalter (pin de contact ou interrupteur (micro-switch)) [TECHNIQUE]','TECH001','technicien','VALIDE_AQ',298,33,'NORMALE','','ROUGE','2026-06-18 20:22:12.302371','AQ001',NULL),(111,'2026-06-19 14:14:21.633438','','2026-06-19 14:11:46.178484','CL001',NULL,NULL,'2026-06-20','Vérifier et réparer ou remplacer les instruments de contrôle et de mesure non fonctionnels.\n\nAutres non-conformités à traiter : 1. Vérifier l\'existance et le bon fonctionnement des instruments de contrôle et de mesure (palmer règles caméra USB pince dénudage loupe; scanner calculatrice si elle est utilisé) [QUALITE]\n2. Vérifier le fonctionnement du \"Poka Yoke\" existant sur la machine: CFM /CFA, Cut module(C1),Système de scannage (capteur présence outil C1 capteur présence contact C1 ) [QUALITE]','TECH001','technicien','VALIDE_AQ',299,33,'NORMALE','','ROUGE','2026-06-19 14:18:41.794153','AQ001',NULL);
/*!40000 ALTER TABLE `plan_action` ENABLE KEYS */;
UNLOCK TABLES;

